package com.macrotracker.widget

import android.content.Context
import androidx.compose.runtime.Composable
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.dp
import androidx.glance.GlanceId
import androidx.glance.GlanceModifier
import androidx.glance.GlanceTheme
import androidx.glance.LocalSize
import androidx.glance.action.actionStartActivity
import androidx.glance.action.clickable
import androidx.glance.appwidget.GlanceAppWidget
import androidx.glance.appwidget.SizeMode
import androidx.glance.appwidget.cornerRadius
import androidx.glance.appwidget.provideContent
import androidx.glance.background
import androidx.glance.layout.Alignment
import androidx.glance.layout.Box
import androidx.glance.layout.Column
import androidx.glance.layout.Row
import androidx.glance.layout.Spacer
import androidx.glance.layout.fillMaxSize
import androidx.glance.layout.fillMaxWidth
import androidx.glance.layout.height
import androidx.glance.layout.padding
import androidx.glance.layout.width
import androidx.glance.text.FontWeight
import androidx.glance.text.Text
import androidx.glance.text.TextStyle
import androidx.glance.unit.ColorProvider
import com.macrotracker.MainActivity
import androidx.glance.appwidget.lazy.LazyColumn
import androidx.glance.appwidget.lazy.items

/**
 * Weather widget — 2×2 to 5×3.
 * TINY    (2×2)   — icon + temp hero + condition
 * COMPACT (*×2)   — header + temp card + hourly strip
 * MEDIUM  (2-3×3) — header + location + temp card + hourly + details
 * FULL    (4-5×3) — header + location + temp card + hourly + detail cards + AI
 */
class WeatherWidget : GlanceAppWidget() {
    override val sizeMode = SizeMode.Single
    override suspend fun provideGlance(context: Context, id: GlanceId) {
        val data = DashboardWidgetDataProvider.loadData(context)
        provideContent { GlanceTheme { WeatherRoot(data) } }
    }
}

@Composable
private fun WeatherRoot(data: DashboardWidgetData) {
    val sz = LocalSize.current
    val ws = classify(sz.width, sz.height)
    val c  = WidgetClr()
    val sc = WScale.from()
    Box(
        modifier = GlanceModifier.fillMaxSize().cornerRadius(sc.corner).background(c.bg)
            .clickable(actionStartActivity<MainActivity>()).padding(sc.pad),
    ) {
        when (ws) {
            WSize.TINY    -> WeatherTiny(data, c, sc)
            WSize.COMPACT -> WeatherCompact(data, c, sc, sz.width)
            WSize.MEDIUM  -> WeatherMedium(data, c, sc, sz.width)
            WSize.FULL    -> WeatherFull(data, c, sc, sz.width)
        }
    }
}

// ── TINY ─────────────────────────────────────────────────────────
@Composable
private fun WeatherTiny(d: DashboardWidgetData, c: WidgetClr, sc: WScale) {
    if (!d.hasWeatherData) {
        Box(GlanceModifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            NoDataPlaceholder("", "No weather", c, sc)
        }
        return
    }
    Column(
        GlanceModifier.fillMaxSize(),
        verticalAlignment = Alignment.CenterVertically,
        horizontalAlignment = Alignment.CenterHorizontally,
    ) {
        Text(d.weatherIcon ?: "️", style = TextStyle(fontSize = sc.iconHero))
        Spacer(GlanceModifier.height(sc.spaceSm))
        Text(
            "${d.weatherTemp}°",
            style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fxxl, color = c.weather),
        )
        val desc = d.weatherDescription?.replaceFirstChar { it.uppercase() } ?: ""
        if (desc.isNotBlank())
            Text(desc, style = TextStyle(fontSize = sc.fsm, color = c.sub), maxLines = 1)
        if (d.weatherHigh != null && d.weatherLow != null) {
            Spacer(GlanceModifier.height(sc.spaceXs))
            Row(verticalAlignment = Alignment.CenterVertically) {
                Text("↑${d.weatherHigh}°", style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fsm, color = c.cal))
                Spacer(GlanceModifier.width(sc.spaceSm))
                Text("↓${d.weatherLow}°", style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fsm, color = c.steps))
            }
        }
    }
}

// ── COMPACT ──────────────────────────────────────────────────────
@Composable
private fun WeatherCompact(d: DashboardWidgetData, c: WidgetClr, sc: WScale, w: Dp) {
    Column(GlanceModifier.fillMaxSize()) {
        WidgetHeader(title = "Weather", c = c, sc = sc, lastUpdatedAt = d.lastUpdatedAt, accent = c.weather)
        if (!d.hasWeatherData) {
            Spacer(GlanceModifier.defaultWeight())
            NoDataPlaceholder("", "No weather data", c, sc)
            Spacer(GlanceModifier.defaultWeight())
        } else {
            Spacer(GlanceModifier.height(sc.spaceSm))
            // Main temp card (less prominent, fit more)
            Box(
                GlanceModifier.fillMaxWidth().cornerRadius(sc.cornerSm).background(c.card)
                    .padding(horizontal = sc.padSm, vertical = sc.spaceSm),
            ) {
                Row(GlanceModifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                    Text(d.weatherIcon ?: "️", style = TextStyle(fontSize = sc.iconHero))
                    Spacer(GlanceModifier.width(sc.spaceSm))
                    Column(GlanceModifier.defaultWeight()) {
                        Text(
                            "${d.weatherTemp}°",
                            style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fxxl, color = c.weather),
                        )
                        val desc = d.weatherDescription?.replaceFirstChar { it.uppercase() } ?: ""
                        if (desc.isNotBlank())
                            Text(desc, style = TextStyle(fontSize = sc.fsm, color = c.sub), maxLines = 1)
                    }
                    // Maximize space: Show sunrise/sunset/wind as compact text right in the main card if space
                    if (d.weatherSunrise != null) {
                         Column(horizontalAlignment = Alignment.End) {
                             Text(" ${d.weatherSunrise}", style = TextStyle(fontSize = sc.fxs, color = c.sub), maxLines = 1)
                             if (d.weatherSunset != null)
                                Text(" ${d.weatherSunset}", style = TextStyle(fontSize = sc.fxs, color = c.sub), maxLines = 1)
                             if (d.weatherWindSpeed != null)
                                Text(" ${d.weatherWindSpeed}", style = TextStyle(fontSize = sc.fxs, color = c.sub), maxLines = 1) 
                         }
                    }
                }
            }
            Spacer(GlanceModifier.height(sc.spaceSm))

            // Hourly forecast AND/OR Data Grid
            // If very wide, split space. If not, prioritize Hourly then maybe a small row.
            if (d.hourlyForecast.isNotEmpty()) {
                val maxSlots = when {
                    w >= 340.dp -> 6
                    w >= 260.dp -> 5
                    else -> 4
                }
                HourlyRow(d.hourlyForecast.take(maxSlots), c, sc)
            }

            // Try to fit at least a row of data cards if height permits (might be tight on 2x height)
            // Or just put them in a row below hourly
            Spacer(GlanceModifier.height(sc.spaceSm))
             val detailCards = buildWeatherCards(d, c).take(4)
             if (detailCards.isNotEmpty()) {
                  val cols = minOf(cardCols(w), detailCards.size)
                  CardGrid(detailCards, cols, c, sc, GlanceModifier.fillMaxWidth().defaultWeight(), fillRows = true)
             } else {
                Spacer(GlanceModifier.defaultWeight())
             }
        }
    }
}

// ── MEDIUM ───────────────────────────────────────────────────────
@Composable
private fun WeatherMedium(d: DashboardWidgetData, c: WidgetClr, sc: WScale, w: Dp) {
    val isNarrow = w < 200.dp
    Column(GlanceModifier.fillMaxSize()) {
        WeatherHeaderBlock(d, c, sc)
        if (!d.hasWeatherData) {
            Spacer(GlanceModifier.defaultWeight())
            NoDataPlaceholder("", "No weather data", c, sc)
            Spacer(GlanceModifier.defaultWeight())
        } else {
            Spacer(GlanceModifier.height(sc.spaceSm))
            // Temp card
            Box(
                GlanceModifier.fillMaxWidth().cornerRadius(sc.cornerSm).background(c.card)
                    .padding(horizontal = sc.padSm, vertical = sc.spaceSm),
            ) {
                Row(GlanceModifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                    Text(d.weatherIcon ?: "️", style = TextStyle(fontSize = sc.iconHero))
                    Spacer(GlanceModifier.width(sc.spaceSm))
                    Column(GlanceModifier.defaultWeight()) {
                        Text("${d.weatherTemp}°", style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fxxl, color = c.weather))
                        val desc = d.weatherDescription?.replaceFirstChar { it.uppercase() } ?: ""
                        if (desc.isNotBlank())
                            Text(desc, style = TextStyle(fontSize = sc.fsm, color = c.sub), maxLines = 1)
                    }
                }
            }
            // Hourly
            if (d.hourlyForecast.isNotEmpty()) {
                Spacer(GlanceModifier.height(sc.spaceSm))
                val maxSlots = if (w >= 260.dp) 5 else 3
                HourlyRow(d.hourlyForecast.take(maxSlots), c, sc)
            }

            // Grid of small data boxes
            Spacer(GlanceModifier.height(sc.spaceSm))
            val detailCards = buildWeatherCards(d, c).take(4) // Show top 4 stats
            if (detailCards.isNotEmpty()) {
                val cols = if (isNarrow) 2 else 4
                CardGrid(detailCards, cols, c, sc, GlanceModifier.fillMaxWidth().defaultWeight(), fillRows = true)
            } else {
                 Spacer(GlanceModifier.defaultWeight())
            }
        }
    }
}

// ── FULL ─────────────────────────────────────────────────────────
@Composable
private fun WeatherFull(d: DashboardWidgetData, c: WidgetClr, sc: WScale, w: Dp) {
    if (!d.hasWeatherData) {
        Box(GlanceModifier.fillMaxSize(), contentAlignment = Alignment.Center) {
             NoDataPlaceholder("", "No weather data", c, sc)
        }
        return
    }

    // Outer column: Top section fixed, Bottom section scrollable
    Column(GlanceModifier.fillMaxSize()) {

        // ── FIXED TOP SECTION ──
        // Only essential "at a glance" info: Header, AI, Hero Temp
        Column(GlanceModifier.fillMaxWidth()) {
            // Header
            WeatherHeaderBlock(d, c, sc, showGreeting = true)
            Spacer(GlanceModifier.height(sc.spaceSm))

            // AI Insight (if available)
            if (!d.aiInsightWeather.isNullOrBlank()) {
                 AiInsightBanner(" ${d.aiInsightWeather}", c, sc)
                 Spacer(GlanceModifier.height(sc.spaceSm))
            }

            // Main Hero Card (Cleaned up - Icon + Temp + Description only)
            Box(
                GlanceModifier.fillMaxWidth().cornerRadius(sc.cornerSm).background(c.card)
                    .padding(horizontal = sc.padSm, vertical = sc.spaceSm),
            ) {
                Row(GlanceModifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                    Text(d.weatherIcon ?: "️", style = TextStyle(fontSize = sc.iconHero))
                    Spacer(GlanceModifier.width(sc.spaceMd))
                    Column(GlanceModifier.defaultWeight()) {
                        Text("${d.weatherTemp}°", style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fxxl, color = c.weather))
                        val desc = d.weatherDescription?.replaceFirstChar { it.uppercase() } ?: ""
                        if (desc.isNotBlank())
                            Text(desc, style = TextStyle(fontSize = sc.fsm, color = c.sub), maxLines = 1)
                    }
                }
            }
            // Add a small spacer below fixed content
            Spacer(GlanceModifier.height(sc.spaceSm))
        }

        // ── SCROLLABLE BOTTOM SECTION ──
        // Contains Grid Details + Hourly Forecast
        Box(GlanceModifier.fillMaxWidth().defaultWeight()) {
            LazyColumn(GlanceModifier.fillMaxSize()) {

                // 1. Details Grid (Scrolls with the list now to save fixed space)
                item {
                    FlexibleWeatherGrid(d, c, sc)
                    Spacer(GlanceModifier.height(sc.spaceMd))
                }

                // 2. Hourly Forecast List
                if (d.hourlyForecast.isNotEmpty()) {
                    items(d.hourlyForecast) { slot ->
                        Column(GlanceModifier.fillMaxWidth()) {
                            HourlyListRow(slot, c, sc)
                            Spacer(GlanceModifier.height(4.dp))
                        }
                    }
                }
            }
        }
    }
}

@Composable
private fun HourlyListRow(slot: HourlyForecast, c: WidgetClr, sc: WScale) {
     Row(
        GlanceModifier.fillMaxWidth()
            .cornerRadius(sc.cornerSm)
            .background(c.card)
            .padding(horizontal = sc.padSm, vertical = 6.dp),
        verticalAlignment = Alignment.CenterVertically
     ) {
         // Time
         Text(
             slot.hour, 
             style = TextStyle(fontSize = sc.fsm, color = c.text, fontWeight = FontWeight.Medium),
             modifier = GlanceModifier.width(50.dp)
         )

         // Icon - Increased size for better visibility
         Text(slot.icon, style = TextStyle(fontSize = sc.fxxl))
         Spacer(GlanceModifier.width(sc.spaceSm))

         // Description & Wind
         Column(GlanceModifier.defaultWeight()) {
             if (!slot.description.isNullOrBlank()) {
                Text(slot.description, style = TextStyle(fontSize = sc.fxs, color = c.sub), maxLines = 1)
             }
             if (!slot.windSpeed.isNullOrBlank()) {
                Text(" ${slot.windSpeed}", style = TextStyle(fontSize = sc.fxs, color = c.sub), maxLines = 1)
             }
         }

         // Precip
         if (slot.pop != null && slot.pop > 0) {
             Text("${slot.pop}%", style = TextStyle(fontSize = sc.fxs, color = c.steps))
             Spacer(GlanceModifier.width(sc.spaceSm))
         }

         // Temp
         val tempColor = slot.temp.toIntOrNull()?.let { t ->
            when {
                t >= 25 -> c.cal
                t <= 5  -> c.steps
                else    -> c.weather
            }
         } ?: c.weather

         Text(
             "${slot.temp}°", 
             style = TextStyle(fontSize = sc.fmd, fontWeight = FontWeight.Bold, color = tempColor),
         )
     }
}

// ── Shared composables ───────────────────────────────────────────

@Composable
private fun FlexibleWeatherGrid(d: DashboardWidgetData, c: WidgetClr, sc: WScale) {
    val items = buildWeatherCards(d, c)
    if (items.isEmpty()) return

    Column(GlanceModifier.fillMaxWidth()) {
        // Row 1: 4 items
        val row1 = items.take(4)
        if (row1.isNotEmpty()) {
            Row(GlanceModifier.fillMaxWidth()) {
                row1.forEachIndexed { i, item ->
                    if (i > 0) Spacer(GlanceModifier.width(sc.spaceXs))
                    WeatherDetailBox(item, c, sc, GlanceModifier.defaultWeight())
                }
            }
        }

        // Row 2: remaining items (e.g. 3) - will be wider because fewer items share width
        val row2 = items.drop(4).take(3)
        if (row2.isNotEmpty()) {
            Spacer(GlanceModifier.height(sc.spaceXs))
            Row(GlanceModifier.fillMaxWidth()) {
                row2.forEachIndexed { i, item ->
                    if (i > 0) Spacer(GlanceModifier.width(sc.spaceXs))
                    WeatherDetailBox(item, c, sc, GlanceModifier.defaultWeight())
                }
            }
        }
    }
}

@Composable
private fun WeatherDetailBox(item: CardInfo, c: WidgetClr, sc: WScale, modifier: GlanceModifier) {
    Box(
        modifier
            // Removed fixed height(50.dp) to let it grow naturally
            .cornerRadius(sc.cornerSm).background(c.card)
            .padding(horizontal = sc.spaceXs, vertical = sc.spaceSm),
        contentAlignment = Alignment.Center
    ) {
        Column(horizontalAlignment = Alignment.CenterHorizontally) {
            Text(item.label, style = TextStyle(fontSize = sc.fxs, color = c.sub), maxLines = 1)
            Spacer(GlanceModifier.height(3.dp)) // slightly increased spacer
            Row(verticalAlignment = Alignment.CenterVertically) {
                Text(item.icon, style = TextStyle(fontSize = sc.fsm))
                Spacer(GlanceModifier.width(4.dp))
                Text(
                    item.value,
                    style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fmd, color = item.accent),
                    maxLines = 1
                )
            }
        }
    }
}

@Composable
private fun WeatherHeaderBlock(d: DashboardWidgetData, c: WidgetClr, sc: WScale, showGreeting: Boolean = false) {
    Column(GlanceModifier.fillMaxWidth()) {
        // Use positional argument for title to avoid unresolved reference issue
        WidgetHeader("Weather", c = c, sc = sc, showGreeting = showGreeting, lastUpdatedAt = d.lastUpdatedAt, accent = c.weather)
        if (d.weatherLocation != null) {
            Spacer(GlanceModifier.height(sc.spaceXs))
            Row(verticalAlignment = Alignment.CenterVertically) {
                Text("", style = TextStyle(fontSize = sc.fsm))
                Spacer(GlanceModifier.width(sc.spaceXs))
                Text(d.weatherLocation, style = TextStyle(fontSize = sc.fsm, color = c.sub), maxLines = 1)
            }
        }
    }
}

@Composable
private fun HourlyRow(hours: List<HourlyForecast>, c: WidgetClr, sc: WScale) {
    val sz = LocalSize.current
    val showPop = sz.width >= 200.dp
    Box(
        GlanceModifier.fillMaxWidth().cornerRadius(sc.cornerSm).background(c.card)
            .padding(horizontal = sc.spaceSm, vertical = sc.spaceSm),
    ) {
        Row(GlanceModifier.fillMaxWidth()) {
            hours.forEachIndexed { i, slot ->
                if (i > 0) Spacer(GlanceModifier.width(sc.spaceXs))
                val tempColor: ColorProvider = slot.temp.toIntOrNull()?.let { t ->
                    when {
                        t >= 25 -> c.cal
                        t <= 5  -> c.steps
                        else    -> c.weather
                    }
                } ?: c.weather
                Column(
                    GlanceModifier.defaultWeight(),
                    horizontalAlignment = Alignment.CenterHorizontally,
                ) {
                    Text(slot.hour, style = TextStyle(fontSize = sc.fxs, color = c.sub), maxLines = 1)
                    Spacer(GlanceModifier.height(sc.spaceXs))
                    Text(slot.icon, style = TextStyle(fontSize = sc.iconSm))
                    Spacer(GlanceModifier.height(sc.spaceXs))
                    Text("${slot.temp}°", style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fsm, color = tempColor), maxLines = 1)
                    if (showPop && slot.pop != null && slot.pop > 0) {
                        Spacer(GlanceModifier.height(sc.spaceXs))
                        Text("${slot.pop}%", style = TextStyle(fontWeight = FontWeight.Bold, fontSize = sc.fxs, color = c.steps), maxLines = 1)
                    }
                }
            }
        }
    }
}

private fun buildWeatherCards(d: DashboardWidgetData, c: WidgetClr): List<CardInfo> = buildList {
    // Row 1: High, Low, Feels Like, Wind
    add(CardInfo("↑", "${d.weatherHigh ?: "--"}°", "High", c.cal))
    add(CardInfo("↓", "${d.weatherLow ?: "--"}°", "Low", c.steps))
    add(CardInfo("️", "${d.weatherFeelsLike ?: "--"}°", "Feels", c.weather))
    add(CardInfo("", d.weatherWindSpeed ?: "--", "Wind", c.sub))

    // Row 2: Humidity, Sunrise, Sunset, UV/Precip
    add(CardInfo("", "${d.weatherHumidity ?: "--"}%", "Humid", c.weather))
    add(CardInfo("", d.weatherSunrise ?: "--:--", "Rise", c.cal))
    add(CardInfo("", d.weatherSunset ?: "--:--", "Set", c.steps))
    // Placeholder 8th slot if needed or 3x3 layout
}

package com.macrotracker.widget

import android.content.Context
import androidx.compose.runtime.Composable
import androidx.compose.ui.unit.Dp
